const nodeCrypto = require('crypto');
const net = require('net');
const tls = require('tls');
const https = require('https');
const { URL } = require('url');

const incoming = $json;
const headers = incoming.headers || {};
const body = incoming.body || incoming;
const secret = headers['x-safeguard-secret'] || headers['X-Safeguard-Secret'] || headers['x-SafeGuard-secret'];

if (!secret || secret !== $env.SAFEGUARD_WEBHOOK_TOKEN) {
  return [{ json: { ok: false, providerStatus: 'rejected', message: 'SafeGuard secret header is missing or invalid.' } }];
}

const workpack = body.workpack || {};
const channels = Array.isArray(body.channels) ? body.channels : [];
const recipients = Array.isArray(body.recipients) ? body.recipients : [];
const message = workpack.message || '';
const payload = {
  event: body.event || 'safeguard.workpack.dispatch',
  receivedAt: new Date().toISOString(),
  subject: `[SafeGuard] ${workpack.companyName || workpack.siteName || '현장'} 작업 전 문서팩`,
  channels,
  recipients,
  operatorNote: body.operatorNote || '',
  message,
  text: `${message}\n\n${body.operatorNote || ''}`.trim(),
  workpack,
  documents: workpack.documents || {},
  evidence: workpack.evidence || {},
  meta: {
    messageTarget: workpack.messageTarget || 'manager',
    messageLanguage: workpack.messageLanguage || { code: 'ko', label: '한국어' },
    riskLevel: workpack.riskLevel || '',
    topRisk: workpack.topRisk || ''
  }
};

const env = $env;
const configs = {
  email: {
    url: env.SAFEGUARD_EMAIL_WEBHOOK_URL || env.EMAIL_WEBHOOK_URL,
    token: env.SAFEGUARD_EMAIL_WEBHOOK_TOKEN || env.EMAIL_WEBHOOK_TOKEN,
    smtpHost: env.SMTP_HOST,
    smtpPort: env.SMTP_PORT,
    smtpUser: env.SMTP_USER,
    smtpPass: env.SMTP_PASS
  },
  sms: {
    url: env.SAFEGUARD_SMS_WEBHOOK_URL || env.SMS_WEBHOOK_URL,
    token: env.SAFEGUARD_SMS_WEBHOOK_TOKEN || env.SMS_WEBHOOK_TOKEN,
    solapiKey: env.SOLAPI_API_KEY,
    solapiSecret: env.SOLAPI_API_SECRET,
    solapiSender: env.SOLAPI_SENDER,
    solapiBaseUrl: env.SOLAPI_BASE_URL || 'https://api.solapi.com'
  },
  kakao: { url: env.SAFEGUARD_KAKAO_WEBHOOK_URL || env.KAKAO_WEBHOOK_URL, token: env.SAFEGUARD_KAKAO_WEBHOOK_TOKEN || env.KAKAO_WEBHOOK_TOKEN },
  band: { url: env.SAFEGUARD_BAND_WEBHOOK_URL || env.BAND_WEBHOOK_URL, token: env.SAFEGUARD_BAND_WEBHOOK_TOKEN || env.BAND_WEBHOOK_TOKEN },
  slack: { url: env.SAFEGUARD_SLACK_WEBHOOK_URL || env.SLACK_WEBHOOK_URL, token: env.SAFEGUARD_SLACK_WEBHOOK_TOKEN || env.SLACK_WEBHOOK_TOKEN },
  discord: { url: env.SAFEGUARD_DISCORD_WEBHOOK_URL || env.DISCORD_WEBHOOK_URL, token: env.SAFEGUARD_DISCORD_WEBHOOK_TOKEN || env.DISCORD_WEBHOOK_TOKEN }
};

function normalizePhone(value) {
  return String(value || '').replace(/[^0-9]/g, '');
}

function maskPhone(value) {
  return normalizePhone(value).replace(/(\d{3})\d+(\d{4})/, '$1****$2');
}

function recipientPhones() {
  const phones = [];
  for (const recipient of recipients) {
    const phone = typeof recipient === 'string'
      ? normalizePhone(recipient)
      : normalizePhone(recipient.phone || recipient.mobile || recipient.tel || recipient.value);
    if (phone) phones.push(phone);
  }
  return [...new Set(phones)];
}

function recipientEmails() {
  const emails = [];
  for (const recipient of recipients) {
    const raw = typeof recipient === 'string' ? recipient : recipient.email || recipient.mail || recipient.value || '';
    const email = String(raw).trim();
    if (/^[^s@]+@[^s@]+.[^s@]+$/.test(email)) emails.push(email);
  }
  return [...new Set(emails)];
}

function maskEmail(value) {
  const [name, domain] = String(value || '').split('@');
  if (!domain) return value;
  return `${name.slice(0, 2)}***@${domain}`;
}

function encodeHeader(value) {
  return `=?UTF-8?B?${Buffer.from(String(value), 'utf8').toString('base64')}?=`;
}

function foldBase64(value) {
  return Buffer.from(String(value), 'utf8').toString('base64').replace(/(.{76})/g, '$1\r\n');
}

function hmacSha256Hex(secretValue, value) {
  return nodeCrypto.createHmac('sha256', secretValue).update(value).digest('hex');
}

function postJson(urlValue, headers, body) {
  return new Promise((resolve, reject) => {
    const url = new URL(urlValue);
    const data = JSON.stringify(body);
    const req = https.request({
      method: 'POST',
      hostname: url.hostname,
      port: url.port || 443,
      path: `${url.pathname}${url.search}`,
      headers: { ...headers, 'content-length': Buffer.byteLength(data) },
      timeout: 20000,
    }, (res) => {
      let responseText = '';
      res.setEncoding('utf8');
      res.on('data', (chunk) => { responseText += chunk; });
      res.on('end', () => resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, text: responseText }));
    });
    req.on('timeout', () => req.destroy(new Error('Provider request timed out')));
    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

async function sendSolapiSms(config) {
  if (!config.solapiKey || !config.solapiSecret || !config.solapiSender) {
    return { channel: 'sms', status: 'unconfigured', provider: 'solapi', message: 'Solapi 발송 설정을 확인해야 합니다.' };
  }

  const phones = recipientPhones();
  if (!phones.length) {
    return { channel: 'sms', status: 'unconfigured', provider: 'solapi', message: '문자 수신자 휴대폰 번호가 없어 SMS 발송을 건너뜁니다.' };
  }

  const text = payload.text.slice(0, 900);
  const results = [];
  for (const to of phones) {
    const date = new Date().toISOString();
    const salt = nodeCrypto.randomUUID ? nodeCrypto.randomUUID() : nodeCrypto.randomBytes(16).toString('hex');
    const signature = hmacSha256Hex(config.solapiSecret, date + salt);
    const authorization = `HMAC-SHA256 apiKey=${config.solapiKey}, date=${date}, salt=${salt}, signature=${signature}`;
    const response = await postJson(`${config.solapiBaseUrl}/messages/v4/send`, { 'content-type': 'application/json', authorization }, { message: { to, from: normalizePhone(config.solapiSender), text } });
    results.push({ to: maskPhone(to), ok: response.ok, httpStatus: response.status, response: response.text.slice(0, 240) });
  }

  const sent = results.filter((item) => item.ok).length;
  return {
    channel: 'sms',
    provider: 'solapi',
    status: sent === results.length ? 'sent' : sent > 0 ? 'partial' : 'failed',
    httpStatus: results[0]?.httpStatus,
    message: sent === results.length ? 'Solapi accepted all SMS messages' : 'Solapi SMS dispatch returned errors',
    recipients: results
  };
}
function createSmtpClient(host, port) {
  let socket;
  let buffer = '';
  const waiters = [];

  function attach(nextSocket) {
    socket = nextSocket;
    socket.setEncoding('utf8');
    socket.on('data', (chunk) => {
      buffer += chunk;
      flush();
    });
    socket.on('error', (error) => {
      while (waiters.length) waiters.shift().reject(error);
    });
  }

  function completeResponse(text) {
    const lines = text.split(/\r?\n/).filter(Boolean);
    if (!lines.length) return false;
    const last = lines[lines.length - 1];
    return /^\d{3} /.test(last);
  }

  function flush() {
    if (!waiters.length || !completeResponse(buffer)) return;
    const waiter = waiters.shift();
    const text = buffer;
    buffer = '';
    waiter.resolve(text);
  }

  function read() {
    return new Promise((resolve, reject) => {
      waiters.push({ resolve, reject });
      flush();
    });
  }

  async function expect(prefix) {
    const response = await read();
    const prefixes = Array.isArray(prefix) ? prefix : [prefix];
    if (!prefixes.some((item) => response.startsWith(item))) {
      throw new Error(`SMTP expected ${prefixes.join('/')} but got ${response.slice(0, 120)}`);
    }
    return response;
  }

  async function send(command, prefix) {
    socket.write(`${command}\r\n`);
    return await expect(prefix);
  }

  async function connect() {
    await new Promise((resolve, reject) => {
      const raw = net.connect({ host, port: Number(port || 587) }, resolve);
      raw.once('error', reject);
      attach(raw);
    });
    await expect('220');
  }

  async function startTls() {
    await send('EHLO safeguard.local', '250');
    await send('STARTTLS', '220');
    socket = tls.connect({ socket, servername: host });
    attach(socket);
    await new Promise((resolve, reject) => {
      socket.once('secureConnect', resolve);
      socket.once('error', reject);
    });
    await send('EHLO safeguard.local', '250');
  }

  async function auth(user, pass) {
    await send('AUTH LOGIN', '334');
    await send(Buffer.from(user).toString('base64'), '334');
    await send(Buffer.from(pass).toString('base64'), '235');
  }

  async function mail(from, toList, subject, text) {
    await send(`MAIL FROM:<${from}>`, '250');
    for (const to of toList) await send(`RCPT TO:<${to}>`, ['250', '251']);
    await send('DATA', '354');
    const body = [
      `From: SafeGuard <${from}>`,
      `To: ${toList.join(', ')}`,
      `Subject: ${encodeHeader(subject)}`,
      'MIME-Version: 1.0',
      'Content-Type: text/plain; charset=UTF-8',
      'Content-Transfer-Encoding: base64',
      '',
      foldBase64(text),
      '.',
    ].join('\r\n');
    socket.write(`${body}\r\n`);
    await expect('250');
    await send('QUIT', '221');
  }

  return { connect, startTls, auth, mail };
}

async function sendSmtpEmail(config) {
  if (!config.smtpHost || !config.smtpUser || !config.smtpPass) {
    return { channel: 'email', status: 'unconfigured', provider: 'smtp', message: 'SMTP 발송 설정을 확인해야 합니다.' };
  }
  const emails = recipientEmails();
  if (!emails.length) {
    return { channel: 'email', status: 'unconfigured', provider: 'smtp', message: '메일 수신자 이메일 주소가 없어 이메일 발송을 건너뜁니다.' };
  }
  const client = createSmtpClient(config.smtpHost, config.smtpPort || 587);
  await client.connect();
  await client.startTls();
  await client.auth(config.smtpUser, config.smtpPass);
  await client.mail(config.smtpUser, emails, payload.subject, payload.text);
  return {
    channel: 'email',
    provider: 'smtp',
    status: 'sent',
    message: 'SMTP accepted email message',
    recipients: emails.map(maskEmail)
  };
}

async function sendWebhook(channel, config) {
  if (!config.url) {
    return { channel, status: 'unconfigured', message: `${channel} provider URL is not configured` };
  }

  const sendHeaders = { 'content-type': 'application/json' };
  if (config.token) sendHeaders.authorization = `Bearer ${config.token}`;

  const sendBody = {
    channel,
    subject: payload.subject,
    recipients: payload.recipients,
    message: payload.message,
    text: payload.text,
    operatorNote: payload.operatorNote,
    meta: payload.meta,
    workpack: payload.workpack,
    documents: payload.documents,
    evidence: payload.evidence
  };

  const response = await fetch(config.url, { method: 'POST', headers: sendHeaders, body: JSON.stringify(sendBody) });
  const responseText = await response.text();
  return {
    channel,
    status: response.ok ? 'sent' : 'failed',
    httpStatus: response.status,
    message: response.ok ? `${channel} provider accepted` : responseText.slice(0, 300)
  };
}

async function send(channel) {
  const config = configs[channel] || {};
  try {
    if (channel === 'sms') {
      if (config.url) return await sendWebhook(channel, config);
      return await sendSolapiSms(config);
    }
    if (channel === 'email') {
      if (config.url) return await sendWebhook(channel, config);
      return await sendSmtpEmail(config);
    }
    if (channel === 'band' && !config.url) {
      return { channel, status: 'unconfigured', provider: 'band', message: 'Band API access is pending review' };
    }
    return await sendWebhook(channel, config);
  } catch (error) {
    return { channel, status: 'failed', message: error.message || String(error) };
  }
}

const requested = payload.channels.length ? payload.channels : ['email'];
const results = [];
for (const channel of requested) {
  results.push(await send(channel));
}

const sent = results.filter((item) => item.status === 'sent').length;
const failed = results.filter((item) => item.status === 'failed').length;
const partial = results.filter((item) => item.status === 'partial').length;
const unconfigured = results.filter((item) => item.status === 'unconfigured').length;
const providerStatus = failed > 0 ? (sent > 0 || partial > 0 ? 'partial' : 'failed') : sent > 0 || partial > 0 ? (unconfigured > 0 ? 'partial' : 'sent') : 'unconfigured';
const messageText = providerStatus === 'sent'
  ? 'SafeGuard 문서팩 전파가 완료되었습니다.'
  : providerStatus === 'partial'
    ? 'SafeGuard 문서팩 일부 채널 전파가 완료되었습니다.'
    : providerStatus === 'unconfigured'
      ? 'SafeGuard 전파 요청은 접수됐지만 선택한 채널 중 수신자 또는 연결 설정을 확인해야 하는 채널이 있습니다.'
      : 'SafeGuard 문서팩 전파 중 오류가 발생했습니다.';

return [{
  json: {
    ok: failed === 0,
    workflowRunId: $execution.id,
    providerStatus,
    channelResults: results,
    summary: { requested: requested.length, sent, failed, partial, unconfigured },
    message: messageText,
    subject: payload.subject,
    recipients: payload.recipients.map((recipient) => {
      if (typeof recipient === 'string') {
        return recipient.includes('@') ? maskEmail(recipient) : maskPhone(recipient);
      }
      return { ...recipient, email: recipient.email ? maskEmail(recipient.email) : recipient.email, phone: recipient.phone ? maskPhone(recipient.phone) : recipient.phone };
    }),
    messagePreview: payload.message.slice(0, 240)
  }
}];
